import { ComponentFixture, TestBed, fakeAsync, tick } from '@angular/core/testing';
import { LoginComponent } from './login.component';
import { AuthService } from '../../services/auth.service';
import { Router } from '@angular/router';
import { ReactiveFormsModule } from '@angular/forms';
import { of, throwError } from 'rxjs';

describe('LoginComponent', () => {
    let component: LoginComponent;
    let fixture: ComponentFixture<LoginComponent>;
    let authServiceSpy: any;
    let routerSpy: any;

    beforeEach(async () => {
        // Мок на AuthService
        authServiceSpy = jasmine.createSpyObj('AuthService', ['login']);
        routerSpy = { navigate: jasmine.createSpy('navigate') };

        await TestBed.configureTestingModule({
            imports: [ReactiveFormsModule],
            declarations: [LoginComponent],
            providers: [
                { provide: AuthService, useValue: authServiceSpy },
                { provide: Router, useValue: routerSpy }
            ]
        }).compileComponents();
    });

    beforeEach(() => {
        fixture = TestBed.createComponent(LoginComponent);
        component = fixture.componentInstance;
        fixture.detectChanges();
    });

    it('should create the component', () => {
        expect(component).toBeTruthy();
    });

    it('should initialize the form with empty values', () => {
        const form = component.loginForm;
        expect(form).toBeTruthy();
        expect(form.value.emailOrUsername).toBe('');
        expect(form.value.password).toBe('');
    });

    it('should make the form invalid when empty', () => {
        const form = component.loginForm;
        expect(form.valid).toBeFalse();
    });

    it('should call AuthService.login and navigate on successful login', fakeAsync(() => {
        const form = component.loginForm;
        form.setValue({ emailOrUsername: 'testuser', password: '123456' });

        authServiceSpy.login.and.returnValue(Promise.resolve());

        component.onLogin();
        tick(); // симулира async/await

        expect(authServiceSpy.login).toHaveBeenCalledWith('testuser', '123456');
        expect(routerSpy.navigate).toHaveBeenCalledWith(['/home']);
    }));

    it('should set errorMessage when login fails', fakeAsync(() => {
        const form = component.loginForm;
        form.setValue({ emailOrUsername: 'wronguser', password: 'wrongpass' });

        authServiceSpy.login.and.returnValue(Promise.reject({ message: 'Invalid credentials' }));

        component.onLogin();
        tick();

        expect(component.errorMessage).toBe('Invalid credentials');
        expect(routerSpy.navigate).not.toHaveBeenCalled();
    }));
});
